// TestAttack_CountEmbeddingsInKV_ConcurrentCalls verifies thread-safety when
// multiple goroutines call CountEmbeddingsInKV simultaneously.
func TestAttack_CountEmbeddingsInKV_ConcurrentCalls(t *testing.T) {
	mgr, mockBuckets := setupTestManager(t)
	embeddingBucket := mockBuckets["EMBEDDING_INDEX"]

	// Setup test data
	const recordCount = 50
	for i := 0; i < recordCount; i++ {
		record := &embedding.Record{
			EntityID:    "entity-" + string(rune(i)),
			Vector:      []float32{0.1, 0.2, 0.3},
			ContentHash: "hash-" + string(rune(i)),
			Status:      embedding.StatusGenerated,
			GeneratedAt: time.Now(),
		}
		data, err := json.Marshal(record)
		require.NoError(t, err)
		embeddingBucket.data[record.EntityID] = data
	}

	// Concurrent calls
	const goroutines = 10
	var wg sync.WaitGroup
	results := make(chan int, goroutines)
	errors := make(chan error, goroutines)

	for i := 0; i < goroutines; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			ctx := context.Background()
			count, err := mgr.CountEmbeddingsInKV(ctx)
			if err != nil {
				errors <- err
			} else {
				results <- count
			}
		}()
	}

	wg.Wait()
	close(results)
	close(errors)

	// All calls should succeed with same count
	require.Empty(t, errors, "No errors should occur during concurrent calls")

	var counts []int
	for count := range results {
		counts = append(counts, count)
	}

	require.Len(t, counts, goroutines, "Should have %d results", goroutines)
	for _, count := range counts {
		require.Equal(t, recordCount, count, "All concurrent calls should return same count")
	}
}

